document.addEventListener('DOMContentLoaded', function () {

    var currentPath = window.location.pathname || '';
    var isOnDemand = currentPath.indexOf('/ondemand') !== -1;
    var isSchedule = currentPath.indexOf('/schedule') !== -1;
    var isPodcasts = currentPath.indexOf('/podcasts') !== -1;
    var isSubPage = isOnDemand || isSchedule || isPodcasts;
    var vueContainerId = isOnDemand ? 'station-on-demand' : isSchedule ? 'station-schedule' : isPodcasts ? 'station-podcasts' : null;

    var BRANDING = {
        beatzone: { logoSrc: 'https://i.8upload.com/image/7885174fadeba731/beatzone2.png', logoAlt: 'BeatZone Radio', slogan: 'Feel the Beat, Live the Music' },
        pescobar: { logoSrc: 'https://pescobar.radio/wp-content/uploads/2025/04/logo_pescobar_radio_blue_background@512x.png', logoAlt: 'BeatZone Radio', slogan: 'Deep as the sea' }
    };

    var activeBrand = isSubPage ? BRANDING.beatzone : BRANDING.pescobar;
    var generalObserverStarted = false;
    var vueObserverStarted = false;
    var periodicCheckStarted = false;

    function getCurrentLogoWidth() {
        if (isSubPage) {
            if (window.innerWidth <= 480) return '118px';
            if (window.innerWidth <= 768) return '132px';
            return '150px';
        }
        if (window.innerWidth <= 480) return '95px';
        if (window.innerWidth <= 768) return '108px';
        return '120px';
    }

    function getVueContainer() {
        if (!isSubPage) return null;
        if (vueContainerId) {
            var byId = document.getElementById(vueContainerId);
            if (byId) return byId;
        }
        return document.querySelector('#station-on-demand, #station-schedule, #station-podcasts, .vue-component');
    }

    function ensureFontsLoaded() {
        if (document.querySelector('link[href*="Nunito"]')) return;
        var link = document.createElement('link');
        link.rel = 'stylesheet';
        link.href = 'https://fonts.googleapis.com/css2?family=Nunito:wght@300;400;500;600;700;800;900&display=swap';
        document.head.appendChild(link);
    }

    function injectRuntimeStyles() {
        if (document.getElementById('beatzone-runtime-fixes')) return;
        var style = document.createElement('style');
        style.id = 'beatzone-runtime-fixes';
        style.textContent = '.bz-lw{display:flex;flex-direction:column;align-items:center;justify-content:center;width:100%;text-align:center}.bz-lw img{display:block;height:auto;max-width:90%;object-fit:contain;margin:0 auto 8px auto;border-radius:10px}.bz-lw p{margin:0;padding:0;text-align:center}body.page-minimal #page-wrapper,body.page-minimal #main{position:relative!important;z-index:2!important;overflow:visible!important}body.page-minimal #main{padding-bottom:30px!important}#station-on-demand,#station-schedule,#station-podcasts{position:relative!important;z-index:2!important;width:100%!important;max-width:980px!important;margin:14px auto 0 auto!important;padding:0 14px!important;overflow:visible!important}#station-on-demand .card,#station-schedule .card,#station-podcasts .card,#station-on-demand .full-height-card,#station-schedule .full-height-card,#station-podcasts .full-height-card{width:100%!important;max-width:980px!important;margin:0 auto 24px auto!important;height:auto!important;min-height:0!important;max-height:none!important;position:relative!important;top:auto!important;left:auto!important;right:auto!important;bottom:auto!important;transform:none!important;overflow:visible!important}#station-on-demand .card-body,#station-schedule .card-body,#station-podcasts .card-body{height:auto!important;min-height:0!important;max-height:none!important;overflow:visible!important}#station-on-demand .table-responsive,#station-schedule .table-responsive,#station-podcasts .table-responsive{overflow-x:auto!important;overflow-y:visible!important}footer#footer,#footer,.bz-if{position:relative!important;z-index:3!important;margin-top:20px!important;margin-bottom:10px!important;display:flex!important;flex-direction:column!important;align-items:center!important;justify-content:center!important;visibility:visible!important;opacity:1!important}';
        document.head.appendChild(style);
    }

    function applySubPageLayoutFixes() {
        if (!isSubPage) return;
        document.body.style.overflowX = 'hidden';
        document.body.style.overflowY = 'auto';
        var pageWrapper = document.getElementById('page-wrapper');
        if (pageWrapper) { pageWrapper.style.minHeight = 'auto'; pageWrapper.style.height = 'auto'; pageWrapper.style.paddingBottom = '24px'; pageWrapper.style.overflow = 'visible'; }
        var main = document.getElementById('main');
        if (main) { main.style.minHeight = 'auto'; main.style.height = 'auto'; main.style.paddingBottom = '30px'; main.style.overflow = 'visible'; }
        var container = getVueContainer();
        if (!container) return;
        container.style.maxWidth = '980px';
        container.style.margin = '14px auto 0 auto';
        container.style.padding = '0 14px';
        container.style.position = 'relative';
        container.style.zIndex = '2';
        container.style.overflow = 'visible';
        var cards = container.querySelectorAll('.card, .full-height-card, [class*="full-height"]');
        cards.forEach(function (card) {
            card.style.width = '100%'; card.style.maxWidth = '980px'; card.style.margin = '0 auto 24px auto';
            card.style.height = 'auto'; card.style.minHeight = '0'; card.style.maxHeight = 'none';
            card.style.position = 'relative'; card.style.top = 'auto'; card.style.left = 'auto';
            card.style.right = 'auto'; card.style.bottom = 'auto'; card.style.transform = 'none'; card.style.overflow = 'visible';
        });
        var headers = container.querySelectorAll('.card-header');
        headers.forEach(function (header) { header.style.paddingTop = '18px'; header.style.paddingBottom = '16px'; });
        var bodies = container.querySelectorAll('.card-body');
        bodies.forEach(function (body) { body.style.height = 'auto'; body.style.minHeight = '0'; body.style.maxHeight = 'none'; body.style.overflow = 'visible'; });
        var tables = container.querySelectorAll('.table-responsive');
        tables.forEach(function (tableWrap) { tableWrap.style.overflowX = 'auto'; tableWrap.style.overflowY = 'visible'; });
    }

    function getSubPageInjectionTarget() {
        var container = getVueContainer();
        if (!container) return null;
        return container.querySelector('.card-header') || container.querySelector('.card .card-header') || container.querySelector('.card') || container;
    }

    function buildBrandWrapper(scopeName) {
        var brandWrapper = document.createElement('div');
        brandWrapper.className = 'bz-lw';
        brandWrapper.setAttribute('data-bz-sc', scopeName);
        if (isSubPage) { brandWrapper.style.padding = '6px 0 4px'; brandWrapper.style.marginBottom = '6px'; }
        else { brandWrapper.style.marginBottom = '10px'; }
        var logoImg = document.createElement('img');
        logoImg.src = activeBrand.logoSrc;
        logoImg.alt = activeBrand.logoAlt;
        logoImg.style.width = getCurrentLogoWidth();
        logoImg.style.maxWidth = '90%';
        logoImg.onerror = function () { this.style.display = 'none'; };
        var slogan = document.createElement('p');
        slogan.textContent = activeBrand.slogan;
        slogan.style.fontFamily = 'Nunito, sans-serif';
        slogan.style.fontSize = isSubPage ? '13px' : '14px';
        slogan.style.fontWeight = '400';
        slogan.style.fontStyle = 'italic';
        slogan.style.color = 'rgba(200,179,96,0.85)';
        slogan.style.letterSpacing = '0.5px';
        slogan.style.margin = '0';
        slogan.style.padding = '0';
        brandWrapper.appendChild(logoImg);
        brandWrapper.appendChild(slogan);
        return brandWrapper;
    }

    function styleTitleInTarget(target) {
        if (!target) return;
        var title = target.querySelector('h1, h2, h3, h4, h5, .card-title');
        if (!title) return;
        title.style.fontFamily = 'Nunito, sans-serif';
        title.style.fontWeight = '800';
        title.style.color = '#ffffff';
        title.style.textAlign = 'center';
        title.style.textShadow = 'none';
        title.style.letterSpacing = '0.5px';
        title.style.margin = isSubPage ? '4px auto 0' : '6px auto 0';
        title.style.fontSize = isSubPage ? '22px' : '24px';
    }

    function injectBrandingSubPage() {
        if (!isSubPage) return;
        if (document.querySelector('.bz-lw[data-bz-sc="subpage"]')) return;
        var target = getSubPageInjectionTarget();
        if (!target) return;
        if (target.querySelector('.bz-lw')) return;
        var wrapper = buildBrandWrapper('subpage');
        if (target.firstChild) { target.insertBefore(wrapper, target.firstChild); } else { target.appendChild(wrapper); }
        styleTitleInTarget(target);
    }

    function injectBrandingPlayer() {
        if (isSubPage) return;
        if (document.querySelector('.bz-lw[data-bz-sc="player"]')) return;
        var cardHeader = document.querySelector('.card-header');
        if (!cardHeader) return;
        if (cardHeader.querySelector('.bz-lw')) return;
        var wrapper = buildBrandWrapper('player');
        cardHeader.insertBefore(wrapper, cardHeader.firstChild);
        styleTitleInTarget(cardHeader);
    }

    function injectBranding() {
        if (isSubPage) { injectBrandingSubPage(); } else { injectBrandingPlayer(); }
    }

    function updateInjectedLogoSize() {
        var logo = document.querySelector('.bz-lw img');
        if (!logo) return;
        logo.style.width = getCurrentLogoWidth();
    }

    function centerPlayerCard() {
        if (isSubPage) return;
        var card = document.querySelector('.radio-player-card');
        if (!card) return;
        function handleResize() {
            if (window.innerWidth <= 768) {
                card.style.position = 'fixed'; card.style.top = 'auto'; card.style.bottom = '10px';
                card.style.left = '10px'; card.style.right = '10px'; card.style.transform = 'none';
                card.style.width = 'calc(100% - 20px)';
            } else {
                card.style.position = 'fixed'; card.style.top = '50%'; card.style.left = '50%';
                card.style.bottom = 'auto'; card.style.right = 'auto';
                card.style.transform = 'translate(-50%, -50%)'; card.style.width = '640px';
            }
        }
        handleResize();
        window.addEventListener('resize', handleResize);
    }

    function fixPlaylistButtons() {
        var buttonsContainer = document.querySelectorAll('.card-body.buttons');
        buttonsContainer.forEach(function (container) {
            var allLinks = container.querySelectorAll('a, .btn-link');
            allLinks.forEach(function (link, index) {
                if (index >= 3) {
                    link.style.display = 'none'; link.style.visibility = 'hidden'; link.style.width = '0';
                    link.style.height = '0'; link.style.opacity = '0'; link.style.pointerEvents = 'none';
                    link.style.position = 'absolute'; link.style.left = '-9999px'; return;
                }
                link.style.flex = '0 0 auto'; link.style.width = 'auto'; link.style.maxWidth = '140px';
                link.style.display = 'inline-flex'; link.style.flexDirection = 'column';
                link.style.alignItems = 'center'; link.style.justifyContent = 'center';
                link.style.textAlign = 'center'; link.style.padding = '6px 14px';
                link.style.borderRadius = '8px'; link.style.cursor = 'pointer';
                link.style.textDecoration = 'none'; link.style.color = 'rgba(200,179,96,0.6)';
                link.style.fontFamily = 'Nunito, sans-serif'; link.style.fontSize = '11px';
                link.style.fontWeight = '600'; link.style.background = 'transparent';
                link.style.border = 'none'; link.style.transition = 'all 0.3s ease';
                link.removeEventListener('mouseenter', link._hIn);
                link.removeEventListener('mouseleave', link._hOut);
                link._hIn = function () { this.style.color = '#ECD164'; this.style.background = 'rgba(236,209,100,0.08)'; this.style.transform = 'translateY(-2px)'; };
                link._hOut = function () { this.style.color = 'rgba(200,179,96,0.6)'; this.style.background = 'transparent'; this.style.transform = 'none'; };
                link.addEventListener('mouseenter', link._hIn);
                link.addEventListener('mouseleave', link._hOut);
            });
        });
    }

    function stylePlayerButtons() {
        var allButtons = document.querySelectorAll('button, .btn, [role="button"]');
        allButtons.forEach(function (btn) {
            var ariaLabel = (btn.getAttribute('aria-label') || '').toLowerCase();
            var title = (btn.getAttribute('title') || '').toLowerCase();
            var text = btn.textContent.trim().toLowerCase();
            var classes = (btn.className || '').toLowerCase();
            if (classes.indexOf('btn-close') !== -1 || classes.indexOf('close') !== -1 || ariaLabel === 'close') return;
            if (btn.closest('table') || btn.closest('td') || btn.closest('tbody') || btn.closest('.modal-footer')) return;
            if (btn.closest('.card-body.buttons')) return;
            if (ariaLabel.indexOf('play') !== -1 || title.indexOf('play') !== -1 || classes.indexOf('play') !== -1 || text === 'play' || text === 'ascultă' || text === 'start') {
                Object.assign(btn.style, { background: '#ECD164', border: '2px solid #C8B360', color: '#273852', borderRadius: '50px', fontFamily: 'Nunito, sans-serif', fontWeight: '700', fontSize: '13px', padding: '10px 24px', cursor: 'pointer', boxShadow: '0 3px 12px rgba(236,209,100,0.3)', transition: 'all 0.25s ease', textShadow: 'none' });
            }
            if (ariaLabel.indexOf('stop') !== -1 || title.indexOf('stop') !== -1 || classes.indexOf('stop') !== -1 || text === 'stop' || text === 'oprește') {
                Object.assign(btn.style, { background: 'rgba(39,56,82,0.9)', border: '2px solid rgba(200,179,96,0.45)', color: '#ffffff', borderRadius: '50px', fontFamily: 'Nunito, sans-serif', fontWeight: '600', fontSize: '13px', padding: '10px 24px', cursor: 'pointer', transition: 'all 0.25s ease', textShadow: 'none' });
            }
        });
    }

    function styleRequestButtons() {
        var requestBtns = document.querySelectorAll('table button, table .btn, tbody button, tbody .btn, td button, td .btn, td.shrink button, td.shrink .btn, .btn-sm.btn-primary, button.btn-primary');
        requestBtns.forEach(function (btn) {
            var classes = (btn.className || '').toLowerCase();
            if (classes.indexOf('btn-close') !== -1 || classes.indexOf('close') !== -1 || btn.getAttribute('aria-label') === 'Close') return;
            Object.assign(btn.style, { display: 'inline-flex', alignItems: 'center', justifyContent: 'center', background: '#ECD164', border: '1px solid #C8B360', borderRadius: '100px', color: '#273852', fontFamily: 'Nunito, sans-serif', fontSize: '11px', fontWeight: '700', padding: '7px 18px', minWidth: '85px', minHeight: '32px', cursor: 'pointer', textShadow: 'none', boxShadow: '0 2px 10px rgba(200,179,96,0.25)', visibility: 'visible', opacity: '1', pointerEvents: 'auto', position: 'relative', zIndex: '100', transition: 'all 0.25s ease', transform: 'none', textTransform: 'none', letterSpacing: '0.3px' });
            btn.removeEventListener('mouseenter', btn._hoverIn);
            btn.removeEventListener('mouseleave', btn._hoverOut);
            btn._hoverIn = function () { this.style.background = '#CFB64E'; this.style.transform = 'translateY(-2px)'; this.style.boxShadow = '0 5px 18px rgba(200,179,96,0.4)'; };
            btn._hoverOut = function () { this.style.background = '#ECD164'; this.style.transform = 'none'; this.style.boxShadow = '0 2px 10px rgba(200,179,96,0.25)'; };
            btn.addEventListener('mouseenter', btn._hoverIn);
            btn.addEventListener('mouseleave', btn._hoverOut);
        });
    }

    function styleModalButtons() {
        var modalBtns = document.querySelectorAll('.modal-footer button, .modal-footer .btn');
        modalBtns.forEach(function (btn) {
            var classes = (btn.className || '').toLowerCase();
            if (classes.indexOf('btn-close') !== -1 || classes.indexOf('close') !== -1) return;
            Object.assign(btn.style, { background: '#ECD164', border: '1px solid #C8B360', borderRadius: '100px', color: '#273852', fontFamily: 'Nunito, sans-serif', fontSize: '12px', fontWeight: '700', padding: '10px 22px', cursor: 'pointer', textShadow: 'none', transition: 'all 0.25s ease' });
        });
    }

    function getOrCreateFooter() {
        var footer = document.querySelector('#footer, footer, .footer, .footer-alt, footer#footer');
        if (footer) return footer;
        footer = document.createElement('footer');
        footer.id = 'footer';
        footer.className = 'bz-if';
        var pageWrapper = document.getElementById('page-wrapper');
        if (pageWrapper) { pageWrapper.appendChild(footer); } else { document.body.appendChild(footer); }
        return footer;
    }

    function customizeFooter() {
        var footer = getOrCreateFooter();
        if (!footer) return;
        if (footer.querySelector('.beatzone-footer-content')) {
            footer.style.textAlign = 'center'; footer.style.padding = '20px 16px';
            footer.style.background = 'transparent'; footer.style.position = 'relative';
            footer.style.zIndex = '3'; footer.style.marginTop = '20px';
            footer.style.display = 'flex'; footer.style.flexDirection = 'column';
            footer.style.alignItems = 'center'; footer.style.justifyContent = 'center';
            return;
        }
        footer.innerHTML = '';
        footer.style.textAlign = 'center'; footer.style.padding = '20px 16px';
        footer.style.background = 'transparent'; footer.style.position = 'relative';
        footer.style.zIndex = '3'; footer.style.marginTop = '20px';
        footer.style.display = 'flex'; footer.style.flexDirection = 'column';
        footer.style.alignItems = 'center'; footer.style.justifyContent = 'center';
        var footerContent = document.createElement('div');
        footerContent.className = 'beatzone-footer-content';
        footerContent.style.cssText = 'display:flex;flex-direction:column;align-items:center;justify-content:center;text-align:center;width:100%;max-width:500px;margin:0 auto;padding:14px 16px;';
        var copyrightLine = document.createElement('p');
        copyrightLine.className = 'bz-copyright';
        copyrightLine.style.cssText = 'display:block;width:100%;margin:0 0 6px 0;padding:0;font-family:"Comic Sans MS","Comic Sans",cursive;font-size:14px;font-weight:bold;color:#ECD164;text-align:center;text-shadow:0 0 10px rgba(236,209,100,0.5),1px 1px 3px rgba(0,0,0,0.8);letter-spacing:0.5px;line-height:1.6;';
        copyrightLine.textContent = '\u00a9 BeatZone Radio 2026. Toate drepturile rezervate.';
        var separator = document.createElement('span');
        separator.className = 'bz-separator';
        separator.style.cssText = 'display:block;width:220px;height:1px;margin:4px auto 10px auto;padding:0;border:none;background:linear-gradient(90deg,transparent 0%,rgba(200,179,96,0.3) 20%,rgba(236,209,100,0.8) 50%,rgba(200,179,96,0.3) 80%,transparent 100%);';
        var creditLine = document.createElement('p');
        creditLine.className = 'bz-madeby';
        creditLine.style.cssText = 'display:block;width:100%;margin:0;padding:0;font-family:"Comic Sans MS","Comic Sans",cursive;font-size:13px;color:#ffffff;text-align:center;text-shadow:0 0 8px rgba(255,255,255,0.3),1px 1px 3px rgba(0,0,0,0.8);letter-spacing:0.3px;line-height:1.6;';
        creditLine.innerHTML = 'Made with <span class="bz-emoji" style="font-size:15px;display:inline-block;vertical-align:middle;margin:0 2px;">&#10084;&#65039;</span> and lots of <span class="bz-emoji" style="font-size:15px;display:inline-block;vertical-align:middle;margin:0 2px;">&#9749;</span> by <a href="https://kaidz.eu" target="_blank" rel="noopener" style="font-family:\'Comic Sans MS\',\'Comic Sans\',cursive;color:#ECD164;text-decoration:none;font-weight:bold;text-shadow:0 0 10px rgba(236,209,100,0.6),1px 1px 3px rgba(0,0,0,0.8);transition:all 0.3s ease;" onmouseover="this.style.color=\'#ffffff\';this.style.textShadow=\'0 0 15px rgba(255,255,255,0.7),0 0 30px rgba(236,209,100,0.4)\';" onmouseout="this.style.color=\'#ECD164\';this.style.textShadow=\'0 0 10px rgba(236,209,100,0.6),1px 1px 3px rgba(0,0,0,0.8)\';">KaiDz</a>';
        footerContent.appendChild(copyrightLine);
        footerContent.appendChild(separator);
        footerContent.appendChild(creditLine);
        footer.appendChild(footerContent);
    }

    function watchVueContainer() {
        if (!isSubPage || vueObserverStarted) return;
        vueObserverStarted = true;
        var target = getVueContainer() || document.body;
        var observer = new MutationObserver(function () {
            injectRuntimeStyles(); applySubPageLayoutFixes(); injectBranding(); updateInjectedLogoSize(); customizeFooter();
        });
        observer.observe(target, { childList: true, subtree: true });
    }

    function watchForChanges() {
        if (generalObserverStarted) return;
        generalObserverStarted = true;
        var targetNode = document.querySelector('#app, .public-page, body');
        if (!targetNode) return;
        var debounceTimer = null;
        var observer = new MutationObserver(function (mutations) {
            var hasRelevant = false;
            for (var i = 0; i < mutations.length; i++) {
                if (mutations[i].type === 'childList' && mutations[i].addedNodes.length > 0) { hasRelevant = true; break; }
            }
            if (!hasRelevant) return;
            if (debounceTimer) clearTimeout(debounceTimer);
            debounceTimer = setTimeout(function () {
                injectRuntimeStyles(); applySubPageLayoutFixes(); injectBranding(); updateInjectedLogoSize();
                stylePlayerButtons(); styleRequestButtons(); styleModalButtons(); fixPlaylistButtons(); customizeFooter();
            }, 300);
        });
        observer.observe(targetNode, { childList: true, subtree: true });
    }

    function startPeriodicCheck() {
        if (periodicCheckStarted) return;
        periodicCheckStarted = true;
        setInterval(function () {
            injectRuntimeStyles(); applySubPageLayoutFixes();
            if (!document.querySelector('.bz-lw')) { injectBranding(); }
            updateInjectedLogoSize();
            var sampleBtn = document.querySelector('td button, td .btn');
            if (sampleBtn) {
                var currentBg = window.getComputedStyle(sampleBtn).backgroundColor;
                if (currentBg.indexOf('236') === -1 && currentBg.indexOf('207') === -1) { styleRequestButtons(); }
            }
            customizeFooter();
        }, 4000);
    }

    function applyFullTheme() {
        ensureFontsLoaded(); injectRuntimeStyles(); applySubPageLayoutFixes();
        injectBranding(); updateInjectedLogoSize(); centerPlayerCard();
        fixPlaylistButtons(); stylePlayerButtons(); styleRequestButtons(); styleModalButtons(); customizeFooter();
    }

    window.addEventListener('resize', function () { applySubPageLayoutFixes(); updateInjectedLogoSize(); });

    watchVueContainer(); watchForChanges(); startPeriodicCheck();
    applyFullTheme();
    setTimeout(applyFullTheme, 400);
    setTimeout(applyFullTheme, 1000);
    setTimeout(applyFullTheme, 2000);
    setTimeout(applyFullTheme, 3500);
    setTimeout(applyFullTheme, 5000);
});
